import React from "react";
import { motion, useAnimation } from "framer-motion";
import { useInView } from "react-intersection-observer";

const About = (props) => {
  const controls = useAnimation();
  const [ref, inView] = useInView({ threshold: 0.3 });

  React.useEffect(() => {
    if (inView) {
      controls.start("visible");
    } else {
      controls.start("hidden");
    }
  }, [inView, controls]);

  let sectionName, hello, about, profilePic;
  if (props.resumeBasicInfo) {
    sectionName = props.resumeBasicInfo.section_name.about;
    hello = props.resumeBasicInfo.description_header;
    about = props.resumeBasicInfo.description;
  }

  // Assuming your profile pic is in sharedData
  if (props.sharedData) {
    profilePic = "images/" + props.sharedData.image;
  }

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.3 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6 } }
  };

  return (
    <section id="about" ref={ref} style={{ padding: "100px 0", position: "relative", overflow: "hidden" }}>
      {/* Decorative Floating Blobs */}
      <motion.div 
        animate={{ 
          scale: [1, 1.2, 1],
          x: [0, 30, 0],
          y: [0, 50, 0] 
        }}
        transition={{ duration: 10, repeat: Infinity, ease: "easeInOut" }}
        style={{
          position: "absolute",
          top: "10%",
          left: "5%",
          width: "300px",
          height: "300px",
          background: "radial-gradient(circle, rgba(233,213,161,0.3) 0%, rgba(186,170,128,0) 70%)",
          filter: "blur(40px)",
          zIndex: -1
        }}
      />

      <div className="container">
        <motion.div 
          className="row"
          initial="hidden"
          animate={controls}
          variants={containerVariants}
        >
          <div className="col-md-12">
            <motion.h1 
              variants={itemVariants}
              style={{ textAlign: "center", marginBottom: "60px", fontWeight: "700", letterSpacing: "2px" }}
            >
              {sectionName}
            </motion.h1>
          </div>

          {/* Profile Picture Column */}
          <div className="col-md-4 mb-5 center">
            <motion.div 
              variants={itemVariants}
              style={{ position: "relative", width: "250px", height: "300px" }}
            >
              {/* <img
                src={"public/images/myProfile.jpg"}
                alt="Profile"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  borderRadius: "20px",
                  boxShadow: "0 20px 40px rgba(0,0,0,0.1)"
                }} */}
              />
              {/* Abstract frame behind image */}
              <div style={{
                position: "absolute",
                top: "20px",
                left: "20px",
                width: "100%",
                height: "100%",
                border: "2px solid #AE944F",
                borderRadius: "20px",
                zIndex: -1
              }} />
            </motion.div>
          </div>

          {/* Bio Column */}
          <div className="col-md-8">
            <motion.div 
              variants={itemVariants}
              style={{
                background: "rgba(255, 255, 255, 0.6)",
                backdropFilter: "blur(10px)",
                padding: "40px",
                borderRadius: "24px",
                border: "1px solid rgba(255, 255, 255, 0.3)",
                boxShadow: "0 10px 30px rgba(0,0,0,0.05)"
              }}
            >
              <h2 style={{ marginBottom: "20px", fontWeight: "600" }}>
                {hello} <motion.span 
                  animate={{ rotate: [0, 20, 0] }} 
                  transition={{ repeat: Infinity, duration: 2 }}
                  style={{ display: "inline-block" }}
                >👋</motion.span>
              </h2>
              <p style={{ 
                fontSize: "1.1rem", 
                lineHeight: "1.8", 
                color: "#444",
                textAlign: "justify" 
              }}>
                {about}
              </p>
            </motion.div>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default About;
